    56→
    57→  const finalPrice = pointsPrice || 0;
    58→  const [pointsValue, setPointsValue] = useState('');
    59→  const [reaisValue, setReaisValue] = useState('');
    60→  const [pointsError, setPointsError] = useState(false);
    61→  const [reaisError, setReaisError] = useState(false);
    62→  const convertionPrice = pointsQuantity * conversionFactor;
    63→  const convertionValue = new Intl.NumberFormat('pt-BR', {
    64→    style: 'currency',
    65→    currency: 'BRL',
    66→  }).format(convertionPrice);
    67→
    68→  const handleGoBack = () => {
    69→    navigation.goBack();
    70→  };
    71→
    72→  const handleContinue = () => {
    73→    eventSelectContent({
    74→      content_type: 'cta',
    75→      content_id: 'continuar',
    76→      location_1: 'monetizacao',
    77→      location_2: 'hub_recompensas_spmais',
    78→      location_3: 'desconto_fatura',
    79→    });
    80→
    81→    const reaisValue = conversionFactor * getParsePoints(pointsValue);
    82→
    83→    navigation.navigate('InvoiceCashbackSummary', {
    84→      pointsSelected: getParsePoints(pointsValue),
    85→      reaisSelected: reaisValue,
    86→      conversionFactor,
    87→      productCode: route?.params?.productCode,
    88→      campaingId: route?.params?.campaingId,
    89→    });
    90→  };
    91→
    92→  const invoiceList = (): CashbackInvoiceItem[] => {
    93→    return [
    94→      {
    95→        type: 'default',
    96→        icon: 'icon-switch-vertical',
    97→        iconColor: 'BRAND_BASE_01',
    98→        iconColorShape: 'INTENSE_COLOR_01',
    99→        description: `Cada ${pointsQuantity.toLocaleString(
   100→          'pt-br'
   101→        )} pontos valem ${convertionValue} no cashback`,
   102→      },
   103→      {
   104→        type: 'default',
   105→        icon: 'icon-calendar',
   106→        iconColor: 'BRAND_BASE_01',
   107→        iconColorShape: 'INTENSE_COLOR_01',
   108→        description: 'Você define quanto cashback quer aplicar na sua fatura aberta',
   109→      },
   110→      {
   111→        type: 'default',
   112→        icon: 'icon-payment-invoice',
   113→        iconColor: 'BRAND_BASE_01',
   114→        iconColorShape: 'INTENSE_COLOR_01',
   115→        description: 'Se o valor for maior que o da fatura, a diferença será aplicada nas próximas',
   116→      },
   117→      {
   118→        type: 'default',
   119→        icon: 'icon-clock',
   120→        iconColor: 'BRAND_BASE_01',
   121→        iconColorShape: 'INTENSE_COLOR_01',
   122→        description: 'O cashback acontece em até 72h',
   123→      },
   124→    ];
   125→  };
   126→  const rate = useMemo(() => {
   127→    if (conversionFactor && conversionFactor > 0) {
   128→      return conversionFactor;
   129→    }
   130→    return 0;
   131→  }, [conversionFactor]);
   132→
   133→  const items: CashbackInvoiceItem[] = invoiceList();
   134→
   135→  const handleChangePoints = (text: string) => {
   136→    const val = getParsePoints(text);
   137→    const formatted = val ? getFormattedPoints(val) : '';
   138→    setPointsValue(formatted);
   139→
   140→    if (rate > 0) {
   141→      setReaisValue(val > 0 ? formatCurrencyBR(val * rate) : '');
   142→    }
   143→    if (val > (Math.trunc(Number(points)) || 0)) {
   144→      setPointsError(true);
   145→    } else {
   146→      setPointsError(false);
   147→    }
   148→  };
   149→
   150→  const handleChangeReais = (text: string) => {
   151→    const val = getParsedCurrency(text);
   152→    const formatted = val > 0 ? formatCurrencyBR(val) : '';
   153→    setReaisValue(formatted);
   154→
   155→    if (rate > 0) {
   156→      const ptsFromReais = Math.round(val / rate);
   157→      setPointsValue(ptsFromReais > 0 ? getFormattedPoints(ptsFromReais) : '');
   158→    }
   159→    if (val > finalPrice) {
   160→      setReaisError(true);
   161→    } else {
   162→      setReaisError(false);
   163→    }
   164→  };
